const item = $input.first();
const data = item.json;
let output = [];

// ===============================
// CONFIG: NÚMEROS DA INSTÂNCIA
// ===============================
// Coloque aqui TODOS os números de instância (sem @s.whatsapp.net, só dígitos)
// Exemplo: seu número Evolution = 553131576672
const INSTANCE_NUMBERS = [
  '553131576672',
  // '55DDDNXXXXXXXX', // adicione outros se tiver
];

// Detecta se é Telegram
const isTelegram = data?.message?.from?.id !== undefined;

// Detecta se é Evolution (WhatsApp Webhook)
const isEvolution =
  data?.body?.event === 'messages.upsert' ||
  data?.body?.data?.key?.remoteJid !== undefined;

// Função: encontra TODOS os telefones BR em uma string (55 + DDD + número 8/9 dígitos)
function findBrazilPhones(str) {
  if (!str) return [];
  const digits = String(str).replace(/\D/g, '');
  const regex = /55\d{10,11}/g; // 55 + 2 dígitos DDD + 8 ou 9 dígitos
  const results = [];
  let match;
  while ((match = regex.exec(digits)) !== null) {
    results.push(match[0]);
  }
  return results;
}

// Pega o PRIMEIRO número que não seja de instância
function getFirstNonInstanceNumberFromString(str) {
  const phones = findBrazilPhones(str);
  const nonInstance = phones.find(p => !INSTANCE_NUMBERS.includes(p));
  return nonInstance || null;
}

// Função que tenta achar o JID do WhatsApp (do CONTATO) no objeto
function extractContactWhatsAppJidFromObject(obj) {
  if (!obj || typeof obj !== 'object') return null;

  // 1) Campos mais prováveis do CONTATO (não usamos body.sender!)
  const candidates = [
    obj?.body?.data?.key?.remoteJidAlt,
    obj?.body?.data?.key?.remoteJid,
    obj?.body?.data?.remoteJidAlt,
    obj?.body?.data?.remoteJid,
    obj?.body?.data?.key?.participant, // útil em grupos
  ];

  for (const cand of candidates) {
    const phone = getFirstNonInstanceNumberFromString(cand);
    if (phone) {
      return `${phone}@s.whatsapp.net`;
    }
  }

  // 2) Fallback: varrer TUDO como string, ignorando números da instância
  const jsonString = JSON.stringify(obj);
  const phone = getFirstNonInstanceNumberFromString(jsonString);
  if (phone) {
    return `${phone}@s.whatsapp.net`;
  }

  return null;
}

if (isTelegram) {
  // *** MESMA LÓGICA QUE O SEU CÓDIGO ORIGINAL ***
  output.push({
    json: {
      source: "telegram",
      message: data.message.text,
      sessionId: data.message.from.id,
    }
  });

} else if (isEvolution) {
  // Evolution (WhatsApp via Evolution)
  const normalizedJid =
    extractContactWhatsAppJidFromObject(data) ||
    data.body.data.key.remoteJid || // fallback extra, caso já venha certinho
    "[jid_nao_encontrado]";

  output.push({
    json: {
      source: "evolution",
      message:
        data.body.data.message?.conversation ||
        data.body.data.message?.extendedTextMessage?.text ||
        "[sem texto]",
      sessionId: normalizedJid,
    }
  });

} else {
  // fallback: payload inesperado
  output.push({
    json: {
      source: "desconhecido",
      raw: data,
      error: "Trigger não reconhecido",
    }
  });
}

return output;

