const input = $input.item.json;

const gifData = input.data?.[0];
if (!gifData) {
  throw new Error("Nenhum GIF encontrado na resposta do GIPHY.");
}

const urlGif = gifData.images.original.url;
const titulo = gifData.title || 'GIF da Lorelai';

return [
  {
    json: {
      gif_url: urlGif,
      titulo: titulo,
      fonte: "GIPHY",
    }
  }
];
